+int message_counter;
+
+void Callback(const sensor_msgs::PointCloud2ConstPtr& msg)
+{
+    message_counter++;
+    std::cout << "Message number " << message_counter <<" received, number of points is: " << msg->width*msg->height << std::endl;
+}
